import AppointmentDetails from "./pages/AppointmentDetails";
import React from "react";
import { Routes, Route, useLocation } from "react-router-dom";
import './App.css';
import { AuthProvider } from "./contexts/AuthContext";
import Home from "./pages/Home";
import ClinicList from "./pages/ClinicList";
import ClinicDetails from "./pages/ClinicDetails";
import BookAppointment from "./pages/BookAppointment";
import RegisterClinic from "./pages/RegisterClinic";
import Login from "./pages/Login";
import ConsultForm from "./pages/ConsultForm";
import ConsultPage from "./pages/ConsultPage";
// import CBCTOPGLabPage from "./pages/CBCTOPGLabPage";
import BloodTestLabPage from "./pages/BloodTestLabPage";
import ShopPage from "./pages/ShopPage";
import ArticlesPage from "./pages/ArticlesPage";
import Header from "./components/Header";
import Footer from "./components/Footer";
import DentistList from "./pages/DentistList.jsx";
import HelpSupport from "./pages/HelpSupport";
import DentistRegistrationForm from "./components/DentistRegistrationForm";
import PricingPlansPage from "./pages/PricingPlansPage";
import CBCTRegistrationForm from "./pages/CBCTRegistrationForm";
import LoginSignup from "./pages/LoginSignup";
import SignUp from "./pages/SignUp";
import DiagnosticLabRegistrationForm from "./pages/DiagnosticLabRegistrationForm";
import PharmaBrandsRegistrationForm from "./pages/PharmaBrandsRegistrationForm";
import BookingPage from "./pages/BookingPage";
import AppointmentConfirmPage from "./pages/AppointmentConfirmPage";
import ConfirmAndPay from "./pages/ConfirmAndPay.jsx";
import ScrollToTop from "./components/ScrollToTop";

function App() {
  const location = useLocation();
  const hideHeader = location.pathname === "/login";
  const noTopPaddingRoutes = ["/dentist-registration", "/cbct-registration"];
  const noTopPadding = noTopPaddingRoutes.includes(location.pathname);

  return (
    <AuthProvider>
      <ScrollToTop />
      {!hideHeader && <Header />}
      <div className={`${noTopPadding ? '' : 'pt-20'} min-h-screen bg-white w-full overflow-x-hidden`}>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/clinics" element={<ClinicList type="clinic" />} />
          <Route path="/clinic/:id" element={<ClinicDetails />} />
          <Route path="/book-appointment" element={<BookAppointment />} />
          <Route path="/register-clinic" element={<RegisterClinic />} />
          <Route path="/login" element={<LoginSignup />} />
          <Route path="/signup" element={<SignUp />} />
          <Route path="/consult" element={<ConsultPage />} />
          <Route path="/consult-form" element={<ConsultForm />} />
          <Route path="/dentist-list" element={<DentistList />} />
          <Route path="/cbct-opg-lab" element={<ClinicList type="cbct" />} />
          <Route path="/blood-test-lab" element={<BloodTestLabPage />} />
          <Route path="/shop" element={<ShopPage />} />
          <Route path="/articles" element={<ArticlesPage />} />
          <Route path="/help" element={<HelpSupport />} />
          <Route path="/dentist-registration" element={<DentistRegistrationForm />} />
          <Route path="/cbct-registration" element={<CBCTRegistrationForm />} />
          <Route path="/diagnostic-lab-registration" element={<DiagnosticLabRegistrationForm />} />
          <Route path="/pricing-plans" element={<PricingPlansPage />} />
          <Route path="/pharma-brands-registration" element={<PharmaBrandsRegistrationForm />} />
          <Route path="/booking" element={<BookingPage />} />
          <Route path="/appointment-confirm" element={<AppointmentConfirmPage />} />
          <Route path="/confirm-pay" element={<ConfirmAndPay />} />
          <Route path="/appointment-details" element={<AppointmentDetails />} />
        </Routes>
      </div>
      <Footer />
    </AuthProvider>
  );
}

export default App;
